var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후후훗, 자 봐라.","JPN":"ふふふっ、さあ見なさい。","ENG":"Hah hah, look.","TWN":"呵呵呵，你們看看。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아무도 너흴 도와주러 오지 못하는구나.","JPN":"誰も貴様らを助けに来ない。","ENG":"No one is coming to help you.","TWN":"沒有人能來幫你們。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"날 봉인에 처박아 넣을 때 나타났던 그 자도……","JPN":"我を封印する時に現れたあの人間も……","ENG":"Even the one who was here when they sealed me...","TWN":"包括把我困在封印時出現的那個人也是……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"결국 지금은 인간의 명을 다하고 죽어버린 거겠지.","JPN":"結局、すでに人間の寿命で死んでしまったのだろう。","ENG":"I suppose he died of old age.","TWN":"最後，現在應該是結束人類的性命的時候。"},"stage":{"bg":"MAINSTREAM_7010013","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"자, 다음은 누가 될까?","JPN":"さあ、次は誰だ？","ENG":"Now, who’s next?","TWN":"那下一個是誰呢？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"인간답게, 제 감정을 주체하지 못하고 덤벼드는 자가……","JPN":"人間らしく、自分の感情を剥き出しにして歯向かう者は……","ENG":"Who will be swayed by their emotions and come at me?","TWN":"像個人類一樣，無法克制自己的情緒撲上來的傢伙……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……당신이 어째서 이렇게까지, 사람을 해치는 괴물이 된 거죠?","JPN":"……あなたはどうしてここまで人を傷つける化け物になってしまったのですか？","ENG":"Why have you become such a monster? Hurting people at whim?","TWN":"……你爲什麼會變成種殘害人類的怪物呢？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"분노가 식은 뒤의 마음은 어느때보다 차가워질 수 있어.","JPN":"怒りが静まった後の心は、いつにも増して冷たくなるもの。","ENG":"When uncontrollable anger ceases, your heart goes cold like a stone.","TWN":"消氣後的心，會比任何時候都冷靜。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그래서 난, 너희 인간들을 전부 없애 버리는 대신, 도움을 주기로 했단다.","JPN":"だから我は、貴様ら人間をすべて滅ぼすかわりに、助けてやることにした。","ENG":"So I decided to help you, instead of annihilating you all.","TWN":"所以，我決定幫助你們，而不是把你們全部消滅掉。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너희 인간들이 더럽혀지기 전에, 내가 직접 그 삶을 거두어가는 거야.","JPN":"貴様ら人間が穢れる前に、我が直接その命をいただくのだ。","ENG":"I will take your lives before you become corrupted.","TWN":"在你們人類受到污染前，我親自去收拾你們的性命。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그리고, 그 영혼으로 이렇게 예쁜 구슬을 만들어서 영원히 내 곁에 두는 거지.","JPN":"そして、その魂でこのような美しい玉を作り、永遠に我のそばに置く。","ENG":"And I will make pretty orbs with your souls to keep with me forever.","TWN":"然後，用靈魂製作出如此美麗的珠子，永遠留在我身邊。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이것이, 너희가 그토록 바라던 영생이란다.","JPN":"これが、貴様らがあれだけ望んでいた永遠の命なのだ。","ENG":"This is the eternal life you’ve been wishing for.","TWN":"這就是你們盼望已久的永生。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"복수로군요.","JPN":"復讐なのですね。","ENG":"You’re taking revenge on us.","TWN":"是報仇嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"인간은 두 손을 가지고 태어나지만.","JPN":"人間は両手を持って生まれるが。","ENG":"You humans have only two hands.","TWN":"人類出生時有雙手，"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"양손을 가득 채우고도 만족이란 걸 하지 못해.","JPN":"その両手をいっぱいにしても満足なぞできぬ。","ENG":"Yet you never know satisfaction, even when both hands are full.","TWN":"但雙手已經都抓滿東西，卻還是不滿足。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그리고 그걸 깨달았을 땐, 그 손에는 이미 누군가의 피가 묻어있겠지.","JPN":"そして、それに気づいた時は、すでにその手を誰かの血で染めているだろう。","ENG":"And when you realize you’ve come too far, your hands are already stained with someone else’s blood.","TWN":"當自己意識到這一點時，那雙手已經沾上別人的血。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"만족을 쫓는 욕망의 끝엔 언제나 후회가 있어.","JPN":"満足を追う欲望の果てには、いつも後悔が待ち構えている。","ENG":"Your desire for satisfaction always ends in regret.","TWN":"追求慾望的最後又總是徒留後悔。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그게 너희 인간이 되풀이하는 실수지.","JPN":"それが貴様ら人間が繰り返す過ちだ。","ENG":"That’s what you humans do, over and over.","TWN":"這就是你們人類一再重蹈覆轍的戲碼。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"해선 안 될 짓을 저지르고, 후회를 하는 짐승만도 못한 존재들.","JPN":"過ちを犯しては後悔する、獣にも劣る存在。","ENG":"You do something that you shouldn’t do, and regret it. You are worse than animals.","TWN":"做不該做的事，然後再來後悔，簡直比禽獸不如。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"난 너무 오랫동안 그 모습을 지켜봐왔어.","JPN":"我はあまりにも長い間、その姿を見守ってきた。","ENG":"I’ve been watching it for too long.","TWN":"這種戲碼一直重複不斷上演。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"지긋지긋해서, 가만히 있을 수 없었지.","JPN":"愛想を尽かしたあまり、じっとしていられなくなったのだ。","ENG":"And I finally grew sick and tired of you.","TWN":"我看膩了，無法再袖手旁觀。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇게 해서 찾은 답이, 고작 사람들을 괴롭히는 일인가요?","JPN":"そうして見つけた答えが、人々を苦しめることだったのですか？","ENG":"So the solution you came up with is to torture us?","TWN":"所以你找到的答案就只是折磨人嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 당신의 생각이 이해 받지 못할 거란 걸 알면서도?","JPN":"そんなあなたの考え方が理解されるはずがないことを知りながらも？","ENG":"Even when you already know that we won’t understand your intentions?","TWN":"就算明知道你這樣的想法不會受到理解？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"벼락이 치면 나무에 불이 붙는단다.","JPN":"雷が鳴れば木に火が宿る。","ENG":"When lightning strikes, it sets a tree on fire.","TWN":" 一道雷劈下，樹會著火。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그 산불은 밑거름이 되어 썩은 뿌리를 지우고 숲을 다시 성장하게 하지.","JPN":"その山火事で腐った根は燃やされ、森は再び成長する。","ENG":"The fire burns the rotten trees and makes way for new buds to grow.","TWN":"那場森林火災成爲基礎，清除腐爛的樹根，使森林重新生長。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"인간들은 그 사실을 잘 알고 있음에도.","JPN":"人間はその事実をよく知っているにもかかわらず。","ENG":"You humans know this, too.","TWN":"雖然人類很清楚這個事實，"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"정작 썩어버린 자신이 벼락을 맞는 운명은 받아들이지 못해.","JPN":"いざ腐ってしまった自分が雷に打たれる運命を受けいれようとしない。","ENG":"But you don’t want to be the tree struck by lightning.","TWN":"卻無法接受腐爛的自己被雷劈。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"운이 나빴다. 누군가의 저주다. 하늘의 뜻이다.","JPN":"運が悪かった。誰かの呪いだ。天の意思だ。","ENG":"You just say you were out of luck, someone cursed you, or it was meant to be...","TWN":"怪運氣不好，怪別人詛咒你，怪上天。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"어떻게든 자신이 탓할 무언가를 만들고 그것을 미워할 뿐이지.","JPN":"そうやって原因にできる何かを作り、それを憎むだけだ。","ENG":"You always blame something else, and hate others for what happened to you.","TWN":"總之就是要找些可以怪罪的理由。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그렇다면 인간의 죽음을 옳다고 판단하는 건 누구일까?","JPN":"では、人間の死を正しいと判断するのは誰だろうか？","ENG":"Then who can justify your death?","TWN":"那誰來判斷人類的死亡是否正確？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아무도 없었어.","JPN":"誰もいなかった。","ENG":"There was no one.","TWN":"沒有人。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"내가 그 역할을 맡기 전까진 그랬지.","JPN":"我がその役割を担う前まではそうだった。","ENG":"Until I came.","TWN":"在我擔負這個責任前是這樣。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어이! 미나토!","JPN":"おい！　湊！","ENG":"Hey, Minato!","TWN":"喂！南裕夏！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"도와주러 왔다!","JPN":"助けにきたぞ！","ENG":"I’m here to help you!","TWN":"我來幫你了！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"네 친구가 왔구나.","JPN":"貴様の友が来たようだな。","ENG":"Your friend is here.","TWN":"你的朋友來了。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"나유카 미나토.","JPN":"奈由香湊。","ENG":"Nayuka Minato.","TWN":"南裕夏。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"잘 봐두렴. 저 아이의 운명을.","JPN":"よく見ておきなさい。あれの運命を。","ENG":"Take a good look at what happens to your friend.","TWN":"你看仔細了，那個人的下場。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키?","JPN":"雅紀？","ENG":"Masaki?","TWN":"雅紀？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"안 돼! 이쪽으로 오면 위험해!","JPN":"ダメだ！　ここは危ない！","ENG":"No! Don’t come any closer!","TWN":"不可以！危險，別過來！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐?","JPN":"あ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"크윽……?!","JPN":"くうっ……！？","ENG":"Urgh?!","TWN":"唔……？！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 방금 눈앞에서 벼락이?","JPN":"な、なんだ？　今目の前に雷が！？","ENG":"W-what? Lightning just struck right in front of my eyes!","TWN":"什…什麼？剛才那是閃電？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……오로치로군요.","JPN":"……オロチですね。","ENG":"It’s Orochi.","TWN":"……是大蛇。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"응? 저 여자가…… 그 무시무시한 오로치의 실체라고?","JPN":"なんだと？　あの女が……恐ろしいオロチの実体だと？","ENG":"Huh? That woman... She’s the horrendous Orochi?","TWN":"嗯？那個女人……可怕的大蛇長那樣？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"지금 미나토의 화살에 맞고 괴로워하는 것 같은데?","JPN":"今、湊の矢に当たって苦しんでいるみたいだが……？","ENG":"But now she’s in pain because of Minato’s arrow.","TWN":"她好像被南裕夏的箭射中很痛苦的樣子。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"내 화살이…… 맞았다고?","JPN":"僕の矢が……当たった？","ENG":"My arrow... hit Orochi?","TWN":"我的箭……射中她了？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"뭐냐, 이건?","JPN":"なんだ、これは？","ENG":"What is this?","TWN":"這是什麼？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"내 예견에는 분명…… 이런 것이 없었는데?","JPN":"我の予見には確かに……このようなモノはなかったはずだが？","ENG":"I didn’t see this in my vision.","TWN":"我明明……沒看見有這種東西？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너…… 대체 뭐하는 녀석이냐?","JPN":"貴様……いったいなにをした？","ENG":"You... What are you?","TWN":"你……到底是誰？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"네가 들었던 미래가, 널 희생해야만 끝나는 미래였다면.","JPN":"君が見た未来が、君を犠牲にして終わる未来だったら。","ENG":"I mean, if you saw the future where all suffering ends with your sacrifice...","TWN":"若你看到的未來，是必須犧牲你才能結束的未來。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이번엔 우리가 그걸 바꿀 수도 있지 않을까?","JPN":"今回は僕たちでそれを変えることもできるんじゃないかな？","ENG":"Maybe we can change that this time, too.","TWN":"這次或許我們可以改變結局？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"そうですね。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"여러분!","JPN":"みなさん！","ENG":"Everyone!","TWN":"各位！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오로치는 힘을 완전히 회복하지 못했습니다. 무녀의 육신에 의탁하고 있다는 게 그 증거입니다.","JPN":"オロチはまだ力を完全に回復していません。\\n巫女の肉体に頼っているのがその証拠です。","ENG":"Orochi is not fully recovered yet. The fact that she’s using the priestess’s body is the proof.","TWN":"大蛇還無法完全恢復力量，證據就是她必須依附在巫女的軀體上。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희가 힘을 합쳐 싸운다면, 어쩌면……","JPN":"私たちが力を合わせて戦えば、もしかしたら……","ENG":"If we combine our forces...","TWN":"如果我們聯手，或許……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오로치를 다시 봉인할 수 있을 지도 모릅니다.","JPN":"オロチを再び封印できるかもしれません。","ENG":"We might be able to seal Orochi once again.","TWN":"或許可以再次封印大蛇。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"좋아! 한 번 해보자고!","JPN":"よし！　一度やってみようじゃねえか！","ENG":"Alright, let’s give it a try!","TWN":"好！就試試看吧！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님의 뜻이 그러시다면, 저도 함께 하겠습니다.","JPN":"当主がそうおっしゃるのなら、私もお供します。","ENG":"If Lady Nanahara wills it, I will follow her.","TWN":"若堂主的意思如此，我也會奉陪的。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미나토님!","JPN":"湊様！","ENG":"Mr. Nayuka!","TWN":"南裕夏！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오래 전, 미나토님의 선조께선 오로치의 봉인에 큰 공헌을 하셨어요.","JPN":"はるか昔、湊様のご先祖様はオロチの封印に大きな貢献をされました。","ENG":"A long time ago, your ancestor contributed greatly to sealing Orochi.","TWN":"很久以前，你的祖先對於封印大蛇有很大的貢獻。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"쏘아올린 화살로 별을 떨어트렸다… 라고 전해지죠.","JPN":"放った矢で星を落とした……と伝わっています。","ENG":"It is said that he shot a star down with his arrow.","TWN":"傳聞說……他們甚至射下星星。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응? 별…… 이라고?","JPN":"え？　星……だって？","ENG":"Huh? A star?","TWN":"嗯？星星…… 嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"잠깐만. 대체 무슨 수로 그런 걸 떨어트리는데?!","JPN":"ちょっと待ってよ。どうやってそんなものを落とすんだ！？","ENG":"Wait, how am I supposed to shoot down a star?","TWN":"等一下，怎麼可能射下星星？！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"실제로 그런 것이 가능했는지는 저도 직접 확인하지 못 했습니다만……","JPN":"実際にそのようなことが可能だったかは\\n私も確認できておりませんが……","ENG":"I don’t know if such a thing is actually possible...","TWN":"雖然我沒實際試過到底可不可能……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나유카 가문이 화살의 힘으로 오로치를 억누를 수 있었던 것은 분명한 사실입니다.","JPN":"奈由香家が矢の力でオロチを抑えることができたのは事実です。","ENG":"But it is true that the arrows of the Nayukas have the power to suppress Orochi.","TWN":"南裕夏家族用箭的力量壓制住大蛇的部分，這一點是事實。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"내…… 조상님이?","JPN":"僕の……ご先祖様が？","ENG":"My ancestor did that?","TWN":"我的……祖先？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응, 알겠어.","JPN":"うん、わかった。","ENG":"Okay.","TWN":"嗯，好吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"별이 될지 뭐가 될지는 모르겠지만……","JPN":"星になるか何になるかはわからないけど……","ENG":"I don’t know if I can shoot down a star...","TWN":"雖然不知道會射下星星還什麼……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"한 번… 이 화살에 내 전력을 쏟아볼게!","JPN":"一度……この矢に僕の全力を注いでみる！","ENG":"But... I’ll try to put all my power into this arrow!","TWN":"我會…盡全力射出這把箭的！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};